// // This module gates power to a device based on the control signal. When control is 1, power_out follows power_in; when control is 0, power_out is always high.
module power_gating (
    input wire control,
    input wire power_in,
    output wire power_out
);
    assign power_out = control ? power_in : 1'b0;
endmodule
